4: using System.Globalization;
5: using Microsoft.JSInterop;
6: 
7: namespace Microsoft.AspNetCore.Components.Routing;
8: 
9: /// <summary>
10: /// A component that can be used to intercept navigation events. 
11: /// </summary>
12: public sealed class NavigationLock : IComponent, IHandleAfterRender, IAsyncDisposable
13: {
14:     private readonly string _id = Guid.NewGuid().ToString("D", CultureInfo.InvariantCulture);
15: 
16:     private RenderHandle _renderHandle;
17:     private IDisposable? _locationChangingRegistration;
18:     private bool _hasLocationChangingHandler;
19:     private bool _confirmExternalNavigation;
20: 
21:     private bool HasLocationChangingHandler => OnBeforeInternalNavigation.HasDelegate;
22: 
23:     [Inject]
24:     private IJSRuntime JSRuntime { get; set; } = default!;
25: 
26:     [Inject]
27:     private NavigationManager NavigationManager { get; set; } = default!;
28: 
29:     /// <summary>
30:     /// Gets or sets a callback to be invoked when an internal navigation event occurs.
31:     /// </summary>
32:     [Parameter]
33:     public EventCallback<LocationChangingContext> OnBeforeInternalNavigation { get; set; }
34: 
35:     /// <summary>
36:     /// Gets or sets whether a browser dialog should prompt the user to either confirm or cancel
37:     /// external navigations.
38:     /// </summary>
39:     [Parameter]
40:     public bool ConfirmExternalNavigation { get; set; }
41: 
42:     void IComponent.Attach(RenderHandle renderHandle)
43:     {
44:         _renderHandle = renderHandle;
45:     }
46: 
47:     Task IComponent.SetParametersAsync(ParameterView parameters)
48:     {
49:         foreach (var parameter in parameters)
50:         {
51:             if (parameter.Name.Equals(nameof(OnBeforeInternalNavigation), StringComparison.OrdinalIgnoreCase))
52:             {
53:                 OnBeforeInternalNavigation = (EventCallback<LocationChangingContext>)parameter.Value;
54:             }
55:             else if (parameter.Name.Equals(nameof(ConfirmExternalNavigation), StringComparison.OrdinalIgnoreCase))
56:             {
57:                 ConfirmExternalNavigation = (bool)parameter.Value;
58:             }
59:             else
60:             {
61:                 throw new ArgumentException($"The component '{nameof(NavigationLock)}' does not accept a parameter with the name '{parameter.Name}'.");
62:             }
63:         }
64: 
65:         if (_hasLocationChangingHandler != HasLocationChangingHandler ||
66:             _confirmExternalNavigation != ConfirmExternalNavigation)
67:         {
68:             _renderHandle.Render(static builder => { });
69:         }
70: 
71:         return Task.CompletedTask;
72:     }
73: 
74:     async Task IHandleAfterRender.OnAfterRenderAsync()
75:     {
76:         if (_hasLocationChangingHandler != HasLocationChangingHandler)
77:         {
78:             _hasLocationChangingHandler = HasLocationChangingHandler;
79:             _locationChangingRegistration?.Dispose();
80:             _locationChangingRegistration = _hasLocationChangingHandler
81:                 ? NavigationManager.RegisterLocationChangingHandler(OnLocationChanging)
82:                 : null;
83:         }
84: 
85:         if (_confirmExternalNavigation != ConfirmExternalNavigation)
86:         {
87:             _confirmExternalNavigation = ConfirmExternalNavigation;
88:             if (_confirmExternalNavigation)
89:             {
90:                 await JSRuntime.InvokeVoidAsync(NavigationLockInterop.EnableNavigationPrompt, _id);
91:             }
92:             else
93:             {
94:                 await JSRuntime.InvokeVoidAsync(NavigationLockInterop.DisableNavigationPrompt, _id);
95:             }
96:         }
97:     }
98: 
99:     private async ValueTask OnLocationChanging(LocationChangingContext context)
100:     {
101:         await OnBeforeInternalNavigation.InvokeAsync(context);
102:     }
103: 
104:     async ValueTask IAsyncDisposable.DisposeAsync()
105:     {
106:         _locationChangingRegistration?.Dispose();
107: 
108:         if (_confirmExternalNavigation)
109:         {
110:             try
111:             {
112:                 await JSRuntime.InvokeVoidAsync(NavigationLockInterop.DisableNavigationPrompt, _id);
113:             }
114:             catch (JSDisconnectedException)
115:             {
116:                 // If the browser is gone, we don't need it to clean up any browser-side state
117:             }
118:         }
119:     }
120: }
